class Solution {
public:
    int lostBits(vector<int>& nums) {
        int res = 0;
        for (int i = 0; i < nums.size(); i++) {
            if (nums[i] == 1) {
                res += nums[i] + 1;
            }
        }
        return res;
    }
};

